from gpio import * from time import * from ioeclient import * from environment import * from physical import *
HUMIDITY_RATE = -2./3600; # -2% per hour TEMPERATURE_RATE = 10./3600; # 10C per hour VOLUME_AT_RATE = 100000.
myinput = 0 state = 0 def setup(): global state IoEClient.setup({ "type": "Furnace", "states": [{ "name": "On", "type": "bool", "controllable": True }] })
IoEClient.onInputReceive(onInputReceiveDone)
add_event_detect(0, detect)
state = restoreProperty("state", 0) setState(state) detect()
VAR = getDeviceProperty(getName(), "VOLUME_AT_RATE") if not VAR: setDeviceProperty(getName(), "VOLUME_AT_RATE", VOLUME_AT_RATE)
def detect(): processData(digitalRead(0)/1023)
def onInputReceiveDone(data): if len(data) <= 0 : return data = data.split(",") processData(int(data[0]))
def restoreProperty(propertyName, defaultValue): value = getDeviceProperty(getName(), propertyName) if not (value is "" or value is None): if type(defaultValue) is int : value = int(value)
setDeviceProperty(getName(), propertyName, value) return value return defaultValue
def setState(newState): global state state = newState setDeviceProperty(getName(), "state", state)
def processData(data): global state, myinput state = data myinput = data if myinput > 0 : digitalWrite(5, HIGH) else: digitalWrite(5, LOW) IoEClient.reportStates(myinput) setDeviceProperty(getName(), "state", state)
def main(): setup() while True: updateEnvironment() delay(1000)
def updateEnvironment(): VAR = float(getDeviceProperty(getName(), "VOLUME_AT_RATE")) if VAR < 0: VAR = 0
humidity_rate = float(myinput*HUMIDITY_RATE*VAR) / Environment.getVolume() temperature_rate = float(myinput*TEMPERATURE_RATE*VAR) / Environment.getVolume() Environment.setContribution("Humidity", humidity_rate, 0, True) Environment.setContribution("Ambient Temperature", temperature_rate, 1000, True) #print temperature_rate, VAR
if __name__ == "__main__": main()

var HUMIDITY_RATE = -2/3600; // -2% per hour
var TEMPERATURE_RATE = 10/3600; // 10C per hour
var VOLUME_AT_RATE = 100000;

var input = 0;
var state = 0;
function setup() {
	IoEClient.setup({
		type: "Furnace",
		states: [{
			name: "On",
			type: "bool",
			controllable: true
		}]
	});

	IoEClient.onInputReceive = function(data) {
		if ( data.length <= 0  )
			return;
		data = data.split(",");
		processData(parseInt(data[0]));
	};

	attachInterrupt(0, function() {
		processData(digitalRead(0)/1023);
	});

	state = restoreProperty("state", 0);
	setState(state);
	
	var VAR = getDeviceProperty(getName(), "VOLUME_AT_RATE");
	if(!VAR)
		setDeviceProperty(getName(), "VOLUME_AT_RATE", VOLUME_AT_RATE);
}

function restoreProperty(propertyName, defaultValue)
{
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ){
		if ( typeof(defaultValue) == "number" )
			value = Number(value);
		
		setDeviceProperty(getName(), propertyName, value);
		return value;
	}
	
	return defaultValue;
}

function setState(newState)
{
	state = newState;
	setDeviceProperty(getName(), "state", state);
}


function processData(data) {
	state = data;
	input = data;
	if ( input > 0 )
		digitalWrite(5, HIGH);
	else
		digitalWrite(5, LOW);
	IoEClient.reportStates(input);
	setDeviceProperty(getName(), "state", state);
}

function loop()
{
	updateEnvironment();
	delay(1000);
}


function updateEnvironment()
{
	var VAR = parseFloat(getDeviceProperty(getName(), "VOLUME_AT_RATE"));
	if( VAR < 0 )
		VAR = VOLUME_AT_RATE;
	//Serial.println("VAR: " + VAR);
	//Serial.println("input: " + input);

	var humidity_rate = input*HUMIDITY_RATE * VAR / Environment.getVolume();
	var temperature_rate = input*TEMPERATURE_RATE * VAR / Environment.getVolume();
	Environment.setContribution("Humidity", humidity_rate);
	Environment.setContribution("Ambient Temperature", temperature_rate);

	//Serial.println("T rate: " + temperature_rate);
	
}

